// "greet" adlı funksiya yaradıram
function greet(name) {
  return "Salam, " + name + "!";
}
console.log(greet("Aysel")); // nəticə: Salam, Aysel!
console.log(greet("Kamran")); // nəticə: Salam, Kamran!

// İki ədədi toplayan funksiya
function addNumbers(a, b) {
  return a + b;
}
console.log(addNumbers(5, 3)); // nəticə: 8
console.log(addNumbers(10, 20)); // nəticə: 30

// Hoisting nümunəsi
console.log(multiply(4, 5)); // nəticə: 20

function multiply(a, b) {
  return a * b;
}

// Returns undefined, çünki return yoxdur
function sayHello() {
  console.log("Hello!");
}
console.log(sayHello()); // nəticə: Hello! və undefined

// Mağaza cəmi hesablama funksiyası
function calculateTotal(price, quantity) {
  return price * quantity;
}
console.log(calculateTotal(10, 2)); // nəticə: 20
console.log(calculateTotal(5, 4)); // nəticə: 20

// Səhər yeməyi planı
function prepareBreakfast(food) {
  return "Səhər yeməyi hazır: " + food;
}
console.log(prepareBreakfast("yumurta")); // nəticə: Səhər yeməyi hazır: yumurta
console.log(prepareBreakfast("tost")); // nəticə: Səhər yeməyi hazır: tost

// Praktik nümunə
function calculateArea(width, height) {
  return width * height;
}
console.log(calculateArea(5, 4)); // nəticə: 20
console.log(calculateArea(3, 6)); // nəticə: 18

